/**
 * @summary Get full traceability results (question → response → evaluation)
 */
export const getGetResultsUrl = (params?: GetResultsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/analytics/results?${stringifiedParams}`
    : `/api/analytics/results`;
};

export const getResults = async (
  params?: GetResultsParams,
  options?: RequestInit,
): Promise<ResultRow[]> => {
  return customFetch<ResultRow[]>(getGetResultsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetResultsQueryKey = (params?: GetResultsParams) => {
  return [`/api/analytics/results`, ...(params ? [params] : [])] as const;
};

export const getGetResultsQueryOptions = <
  TData = Awaited<ReturnType<typeof getResults>>,
  TError = ErrorType<unknown>,
>(
  params?: GetResultsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getResults>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetResultsQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getResults>>> = ({
    signal,
  }) => getResults(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getResults>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetResultsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getResults>>
>;
export type GetResultsQueryError = ErrorType<unknown>;

