/**
 * @summary Save API keys for LLM providers
 */
export const getSaveApiKeysUrl = () => {
  return `/api/settings/api-keys`;
};

export const saveApiKeys = async (
  saveApiKeysBody: SaveApiKeysBody,
  options?: RequestInit,
): Promise<ApiKeyStatus> => {
  return customFetch<ApiKeyStatus>(getSaveApiKeysUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(saveApiKeysBody),
  });
};

export const getSaveApiKeysMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof saveApiKeys>>,
    TError,
    { data: BodyType<SaveApiKeysBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof saveApiKeys>>,
  TError,
  { data: BodyType<SaveApiKeysBody> },
  TContext
> => {
  const mutationKey = ["saveApiKeys"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof saveApiKeys>>,
    { data: BodyType<SaveApiKeysBody> }
  > = (props) => {
    const { data } = props ?? {};

    return saveApiKeys(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type SaveApiKeysMutationResult = NonNullable<
  Awaited<ReturnType<typeof saveApiKeys>>
>;
export type SaveApiKeysMutationBody = BodyType<SaveApiKeysBody>;
export type SaveApiKeysMutationError = ErrorType<unknown>;

/**
 * @summary Save API keys for LLM providers
 */
export const useSaveApiKeys = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof saveApiKeys>>,
    TError,
    { data: BodyType<SaveApiKeysBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof saveApiKeys>>,
  TError,
  { data: BodyType<SaveApiKeysBody> },
  TContext
> => {
  return useMutation(getSaveApiKeysMutationOptions(options));
};
